const jsonMasiv = [];

function findEntities(text) {
  const entities = [
    /\b(присутній|втратила)\s*(журналіст|писемник|публіцист|лауреат)\b/g,
    /\b(Борис Онуфрійович)\b/g,
    /\b(Іvan I. Франк)\b/g,
    /\b(компартійне)\b/g,
    /\b(редактор)\b/g,
    /\b(журналіст)\b/g,
    /\b(судилище)\b/g,
    /\b(штиль|даруйте)\b/g,
    /\b(річка|заплав|пливів|лесу|переміни\w+)\b/g,
  ];

  entities.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "MISC",
        text: matches[0],
      });
    }
  });

  const classes = [
    /\b(присутній)\b/g,
    /\b(втратила)\b/g,
    /\b(журналіст)\b/g,
    /\b(писемник)\b/g,
    /\b(публіцист)\b/g,
    /\b(лауреат)\b/g,
  ];

  classes.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "ART",
        text: matches[0],
      });
    }
  });

  const dates = [
    /\b(1991-му)\b/g,
    /\b(пiselamnyi serpnevyy putch)\b/g,
  ];

  dates.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "PERIOD",
        text: matches[0],
      });
    }
  });

  const locations = [
    /\b(Львові)\b/g,
    /\b(Херсонщина)\b/g,
  ];

  locations.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "LOC",
        text: matches[0],
      });
    }
  });

  const jobs = [
    /\b(прізнیک)\b/g,
    /\b(редактор)\b/g,
    /\b(журналіст)\b/g,
    /\b(судилище)\b/g,
  ];

  jobs.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "JOB",
        text: matches[0],
      });
    }
  });

  const times = [
    /\b(штиль)\b/g,
    /\b(дарйте)\b/g,
  ];

  times.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "TIME",
        text: matches[0],
      });
    }
  });

  const organizations = [
    /\b(компартійне)\b/g,
    /\b(редактор)\b/g,
    /\b(журналіст)\b/g,
  ];

  organizations.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "ORG",
        text: matches[0],
      });
    }
  });

  const persons = [
    /\b(Борис Онуфрійович)\b/g,
    /\b(Іvan I. Франк)\b/g,
  ];

  persons.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "PERS",
        text: matches[0],
      });
    }
  });

  const quantities = [
    /\b(прізнік)\b/g,
    /\b(редактор)\b/g,
    /\b(журналіст)\b/g,
  ];

  quantities.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "QUANT",
        text: matches[0],
      });
    }
  });

  const documents = [
    /\b(редактор)\b/g,
    /\b(журналіст)\b/g,
    /\b(судилище)\b/g,
  ];

  documents.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "DOC",
        text: matches[0],
      });
    }
  });

  const percentages = [
    /\b(штиль)\b/g,
    /\b(дарйте)\b/g,
  ];

  percentages.forEach((regex) => {
    const matches = text.match(regex);
    if (matches) {
      jsonMasiv.push({
        label: "PCT",
        text: matches[0],
      });
    }
  });

  return jsonMasiv;
}

