const result = entities.map((entity) => ({
  label: entity.label,
  text: entity.text ? extractText(text, entity.text) : "",
}));

function extractText(text, pattern) {
  const regex = new RegExp(pattern, "g");
  let match;
  const extractedText = [];
  while ((match = regex.exec(text)) !== null) {
    extractedText.push(match[0]);
  }
  return extractedText.join(" ");
}

