const entities = [];
const words = text.split(' ');

for (let i = 0; i < words.length; i++) {
    const word = words[i].trim();
    if (word.match(/^[A-Z]/)) { // ART
        entities.push({ label: 'ART', text: word });
    } else if (word.match(/^\d{1,2}\/\d{4}$/)) { // DATE
        entities.push({ label: 'DATE', text: word });
    } else if (word.match(/^[A-Z]+[a-z]+$/)) { // DOC
        entities.push({ label: 'DOC', text: word });
    } else if (word.match(/^Prof\.[a-zA-Z ]+$/)) { // JOB
        entities.push({ label: 'JOB', text: word });
    } else if (word.match(/^(Lviv|Kiev|Mistetskyi Arsenal|Ukraine|Europe)/)) { // LOC
        entities.push({ label: 'LOC', text: word });
    } else if (word.match(/^\d+(\.\d+)?$/)) { // MON
        entities.push({ label: 'MON', text: word });
    } else if (word.match(/([A-Z]+)%/)) { // PCT
        entities.push({ label: 'PCT', text: word });
    } else if (word.match(/^From \d{1,2} to \d{1,2}$/)) { // PERIOD
        entities.push({ label: 'PERIOD', text: word });
    } else if (word.match(/^[A-Z]+[a-z]+ [A-Z]+$/)) { // PERS
        entities.push({ label: 'PERS', text: word });
    } else if (word.match(/^\d+$/)) { // QUANT
        entities.push({ label: 'QUANT', text: word });
    } else if (word.match(/^At \d{1,2}:00$/)) { // TIME
        entities.push({ label: 'TIME', text: word });
    } else {
        entities.push({ label: 'MISC', text: word });
    }
}

