const jsonOutput = [];

function extractEntity(text, entity) {
  const regex = new RegExp(entity, 'g');
  const matches = text.match(regex);
  if (matches) {
    return matches.map(match => ({
      label: entity,
      text: match,
    }));
  } else {
    return [];
  }
}

const entities = [
  { name: 'ART', pattern: /потрясно good|добре/g },
  { name: 'DATE', pattern: /3 травня|5 червня/g },
  { name: 'DOC', pattern: /(закон)/g },
  { name: 'JOB', pattern: /(професія)/g },
  { name: 'LOC', pattern: /Львов/ig },
  { name: 'MON', pattern: /30 гривня/g },
  { name: 'ORG', pattern: /SoftServe/g },
  { name: 'PCT', pattern: /50%/g },
  { name: 'PERIOD', pattern: /(від 5 до 30)/ig },
  { name: 'PERS', pattern: /(петро)/ig },
  { name: 'QUANT', pattern: /дванадцять/ig },
  { name: 'TIME', pattern: /15.00/ig },
  { name: 'MISC', pattern: /потрясно good|добре/ig, caseless: true },
];

const sentences = text.split(/[.!?]/);
for (let sentence of sentences) {
  for (let entity of entities) {
    let extractedEntities = extractEntity(sentence, entity.pattern);
    if (entity.pattern.includes(/g/i)) {
      extractedEntities = extractedEntities.map(match => ({ label: entity.name, text: match.text.toUpperCase() }));
    } else if (!entity.pattern.includes('caseless')) {
      extractedEntities = extractedEntities.map(match => ({ label: entity.name, text: match.text.toUpperCase() }));
    }

    jsonOutput = [...jsonOutput, ...extractedEntities];
  }
}

console.log(jsonOutput);

