U rezultata dogojtativysh dolgovytyh diskusiy uchennyh Gryby byli vznachenie otochnim samoostojatelnym tsarstvom, no ne iz Yakstravnno razreshennogo puti izmenenija odnoi starozheleznoj fazy , perforirovania u mezlitinnykh peregorodkakh. 

Do konca XX st. ostanchno sformovasyas prezvestanie o perforirovanii grybya, zagralnovyznanaya ikh heterogennost`,;

 const result = [];

  const sentences = text.split(". ");

for (const sentence of sentences) {
    const words = sentence.split(" ");
    let label = "MISC";
    let text = "";

    for (let i = 0; i < words.length; i++) {
      if (isArtifact(words[i])) {
        label = 'ART';
        text += ` ${words[i]}`;
      } else if (isDate(words[i])) {
        label = 'DATE';
        text += ` ${words[i]}`;
      } else if (isDoc(words[i])) {
        label = 'DOC';
        text += ` ${words[i]}`;
      } else if (isJob(words[i])) {
        label = 'JOB';
        text += ` ${words[i]}`;
      } else if (isLocation(words[i])) {
        label = 'LOC';
        text += ` ${words[i]}`;
      } else if (isMon(words[i])) {
        label = 'MON';
        text += ` ${words[i]}`;
      } else if (isOrg(words[i])) {
        label = 'ORG';
        text += ` ${words[i]}`;
      } else if (isPct(words[i])) {
        label = 'PCT';
        text += ` ${words[i]}`;
      } else if (isPeriod(words[i])) {
        label = 'PERIOD';
        text += ` ${words[i]}`;
      } else if (isPerson(words[i])) {
        label = 'PERS';
        text += ` ${words[i]}`;
      } else if (isQuant(words[i])) {
        label = 'QUANT';
        text += ` ${words[i]}`;
      } else if (isTime(words[i])) {
        label = 'TIME';
        text += ` ${words[i]}`;
      }
    }
   result.push({ label, text });
