 function isArtifact(word) {
   const artWords = ['artifact', 'object'];
   return artWords.includes(word.toLowerCase());
 }

 function isDate(word) {
   const dateWords = ['date', 'kalendarni dati'];
   return dateWords.includes(word.toLowerCase());
 }

 function isDoc(word) {
   const docWords = ['document', 'law', 'treaty', 'passport', 'other documents'];
   return docWords.includes(word.toLowerCase());
 }

 function isJob(word) {
   const jobWords = ['job title', 'profession and occupation'];
   return jobWords.includes(word.toLowerCase());
 }

 function isLocation(word) {
   const locationWords = ['location', 'geographical names'];
   return locationWords.includes(word.toLowerCase());
 }

 function isMon(word) {
   const monWords = ['money', 'quantities of money'];
   return monWords.includes(word.toLowerCase());
 }

 function isOrg(word) {
   const orgWords = ['organization', 'company', 'establishment', 'institution'];
   return orgWords.includes(word.toLowerCase());
 }

 function isPct(word) {
   const pctWords = ['percentage', 'percentages'];
   return pctWords.includes(word.toLowerCase());
 }

 function isPeriod(word) {
   const periodWords = ['period', 'time intervals'];
   return periodWords.includes(word.toLowerCase());
 }

 function isPerson(word) {
   const personWords = ['person name', 'name and surname'];
   return personWords.includes(word.toLowerCase());
}

 function isQuant(word) {
   const quantWords = ['quantity', 'quantities'];
   return quantWords.includes(word.toLowerCase());
 }

 function isTime(word) {
   const timeWords = ['time', 'hours'];
   return timeWords.includes(word.toLowerCase());
}

