const text = `Переможені битви війська Богдана Хмельницького у nacionalno-vyzvolny boroti ukrajinskogo narodu v XVII st . Vizvolna voyna ukrajinskogo narodu protiv panuvania Polshchyi v XVII st . Ocholil gertman Bogdan Khmelnytskyy .`;

const entities = [
  "ART",
  "DATE",
  "DOC",
  "JOB",
  "LOC",
  "MON",
  "ORG",
  "PCT",
  "PERIOD",
  "PERS",
  "QUANT",
  "TIME",
  "MISC"
];

const nlp = require('nlpjs');
const json = [];

const processor = new nlp.TextProcessor();
processor.addEntity({
  name: 'ART',
  pattern: /поточний|білорусь|вірмень/g,
});

processor.addEntity({
  name: 'DOC',
  pattern: /закони|угодя|паспорти/g,
});

processor.addEntity({
  name: 'JOB',
  pattern: /професії|посади/g,
});

processor.addEntity({
  name: 'LOC',
  pattern: /Львові|Корсунь|Пілля|Галичина/g,
});

processor.addEntity({
  name: 'MON',
  pattern: /\(грн|крб|євро)/g,
});

processor.addEntity({
  name: 'ORG',
  pattern: /(SoftServe|українська армія)/gi,
});

processor.addEntity({
  name: 'PCT',
  pattern: /(\d+)%/gi,
});

processor.addEntity({
  name: 'PERIOD',
  pattern: /(\d+) року/gi,
});

processor.addEntity({
  name: 'PERS',
  pattern: /(Богдан Хмельницький|Петро)/gi,
});

processor.addEntity({
  name: 'QUANT',
  pattern: /\(тис./g,
});

processor.addEntity({
  name: 'TIME',
  pattern: /(\d+):(\d+)|(\d+):(\d+):(\d+)/gi,
});

processor.addEntity({
  name: 'MISC',
  pattern: /(жовті|військову)/gi,
});

processor.process(text, (err, result) => {
  if (err) {
    console.error(err);
  } else {
    const entitiesArray = processor.getEntities();
    for (let i = 0; i < entitiesArray.length; i++) {
      json.push({
        label: entities[entitiesArray[i].type],
        text: entitiesArray[i].text
      });
    }
    console.log(json);
  }
});

const text = `Уряд , намагаючись вилучити аграрну продукцію у селян , започаткував політику « ножиць цін » . Її спрямовували на штучне завищення цін на промислові товари і зниження на сільськогосподарську продукцію . Влада вдалася до адміністративного тиску на селян . У результаті , на початку 1928 р . кризу вдалося подолати ( за січень-лютий у республіці було заготовлено 70 млн пудів зерна ) . Але наступної зими 1928-1929 pp . криза повторилася у ще більших масштабах . Радянська влада вбачала у селянстві консервативну силу , що чинила опір державній економічній політиці . Чиновницький апарат виношував плани перетворення селян із приватних господарів на сільськогосподарських робітників , віддалених від власності на засоби виробництва й результатів своєї праці . Першопочатком реформування сільського господарства стала підтримка державою сільськогосподарської кооперації . Влада прагнула мати справу не з окремими сільськими господарями , а з колективами виробників сільськогосподарської продукції . згодом різні форми сільськогосподарської кооперації були зведені до однієї — сільськогосподарської артілі , що її влада трансформувала у колгоспи . У цій ситуації вже не держава залежала від індивідуальних селянських господарств , а сконцентровані у великі спільні господарства селяни підпорядковувались державі . Курс на колективізацію сільського господарства було визначено у грудні 1927 р . на XV з’їзді ВКП ( б ) , а в 1929 р . влада проголосила суцільну колективізацію . Селян почали силоміць заганяти до колгоспів . У відповідь на примусову колективізацію селянство взялося за зброю . Упродовж першого півріччя 1930 р . в Україні було зареєстровано 1,5 тис . терористичних актів проти організаторів колгоспного руху . У Херсонському , Вінницькому , Чернігівському , Одеському та ін . округах відбулися збройні виступи селян за участі понад 40 тис . осіб . Окрім повстань , селяни вдавалися до пасивних форм боротьби ( забиття і продаж худоби , псування реманенту ) . Наприкінці 20-х - на початку 30-х років в Україні поголів'я великої рогатої худоби скоротилося на 41,8 % , свиней — на 62,3 % , овець — на 74 % . За цей час було експропрійовано понад 200 тис . селянських господарств . До колгоспу забирали земля , реманент , худобу , коней та ін . Розкуркулення . Доля приватних сільських господарств Які заходи здійснила влада навесні 1930 p . , щоб заспокоїти селян ? До яких наслідків це призвело ? Коли і яким чином владі вдалося остаточно припинити супротив селянства колективізації ? Якими були безпосередніх наслідков колективізації для сільського господарства України ? Колективізація в Україні супроводжувалася наростанням терору . Особливої жорстокості від нової влади зазнало заможне селянство , яке організатори колгоспного руху охрестили « куркулями » . Офіційна пропаганда зображувала їх ворогами радянської влади і « експлуататорами трудового народу » . Насправді , лише невелика кількість заможних селянських господарств використовували найману працю . В основному вони покладалися на трудові ресурси своїх родин ,ощадливість та хазяйновитість . Проте радянська влада проголосила своїм завданням « ліквідувати куркульство як клас » . Перша хвиля масового розкуркулення почалася з січня 1930 р . і тривала до початку березня . Вона охопила 76 % районів УСРР . Куркулів виселяли на висілки , але в межах України . Восени 1930 р . почалася друга хвиля розкуркулення . Тих , хто підпадав під неї , висيلاли уже за межі республіки . В Україні було « розкуркулено » понад 1 млн селян , з них понад 860 тис . виселили на Північ і до Сибіру . Багато з них загинули . На початку 30-х років радянське керівництво збагнувло , що на селі ситуація стала критичною і нарощувати темпи колективізації украй небезпечно . У березні 1930 р . Й . Сталін опублікував статтю « Запаморочення від успіхів » , де , розігравши роль « доброго батька народів » , засудив насаджування колгоспів силою і звинуватив місцеву владу в перегинах . Слідом за статтею було опубліковано постанову ЦК ВКП ( б ) « Про боротьбу з викривеннями партійної лінії у колгоспному русі » . Місцевим партійцям пропонувалися відмовитися від адміністративного тиску на селян при створенні колгоспів . Тоді ж було опубліковано « Приблизний статут сільськогосподарської артілі » , де колгоспникам дозволялось мати корову , дрібну живність , присадибну ділянку . Прийняті документи заспокоїли селянство . Воно повірило у сталінську « справедливість » і , керуючись тезою « колгосп — справа добровільна » , почало масово виходити з колективних господарств . За три місяці майже половина колективізованих селян в Україні повернулися до індивідуального господарювання . Але згодом з’ясувалося ,що це був тактичний маневр . У вересні 1930 р . влада почала новий наступ на селянство , тепер вона створила такі умови ,що економічно унеможливлювали індивідуальне господарювання . Тим , хто виходив з колгоспів , відводили гірші землі , не повертали худобу і реманент , збільшували оподаткування . Селянам , які опинилися під таким пресом , доводилося повертатися назад до колгоспу . У 1932 р . в УСРР було колективізовано 70 % селянських господарств .`;

