const text = `На цей клич і кидаються діти до Пилипа , — а Тарас уже тут як тут , де й поділася ота безпечність .
Та не дівчат вибирає , котрих ловити легше , Ні , вінsono Дмитрика вполював , сина козака Ситника .
Добрий козак Ситник , і синок у нього славний росте — а бач , уполюнав його « вовк » - Тарас !
Розчулений панотець — іще б пак , який батько хвацьким та прудким сином не пишатиметься — розгортає книжку й заглиблюється в читання .
Ще в Академії роздобув він собі « Четьї Мінеї » , Димитрієм Тупталенком pisані .
Грубі гроші виложив , як на спудея , за ці чотири мудрих томи ; хлопці , однокашники , ще й підсміювалися — звісно , крім Грицька та Євдокима .
З ними він найбільше дружив .
І що ж — мудрий чоловік Грицько все собі місця ніяк не нагріє — то по світах блукає , а то по Вкраїні тепер блукає .
Торік і сюди навідувався — посиділи , погомоніли любісінько , як колись в Академії ...
Розказав , між іншим , що Євдоким постригпід іменем Івана прийняв у Мотронинській пустині .
Цікаво , якийсь з нього чернець ?
Він же завжди таким забіякою був !
Ото Грицькові б у монахови з його мисливим життям .
А Євдокimu — на Січ , там такі одчайдухів тепер бракує .
Ну , але людина чинить , а Бог поправляє .
Лише Йому відомо , де кожного з нас місце на світі ...
Ось його , отця Василія , дякувати Богу , місце тут , на парафії — службу правити , та паству на богоугодне життя навертати , та дітей ростити — добрі будуть священики з Пилипа й Тараса ...
І « Четьї Мінеї » читати — тепер ці чотири томи з ним на все життя лишилися , і дітям своїм передасть .
Уже тут , у Куземині , посівши парафію , у добру шкіру їх оправив , щонеділі душу відводить ...
Оце ж колись , в Академії , і макарівські Житія читав , і грецькі — а душа однак до цих тягнеться .
Ну , бо свої , рідні — козацьким сином pisані .
Хіба ж хто краще від українця українську душу прочує ?
Казав йому нещодавно митрополит , що чував , якби в Ростові мощі Димитрія"netлінні відкрилися .
Не здивувався цьому отець Василь — давно-бо почав , що лише свята людина таку книгу створити може .
Ось лише скільки українських святих у далекій чужині мусили голови свої зложити ...
... « Ащо ж це ви коїте , анциболоти ?! » — мало не скрикнув уголос , зиркувавши у вікно .
Там дітлахам "Гуси , гуси , додому" вже набридли , то вони почали в сракача грати .
Не дуже милозвучно зветься оця гра — ну , але не він таку назву вигадав , то не йому її й міняти .
І Улясю - ото пуцьвірінок — уже нагойдалася , вже й собі до старших ігор тягнеться .
Очі їй хустиною зав’язали , рученята під поперечок долоньками вгору склала — і цілий гурт дітлахів іззаду й замахуються ...
Усі замахуються , а хтось один і вперіщить !
Спробуй-но відгадай , хто саме ...`;
const entities = [
  { label: "PERS", text: /(\w+) (.*)/g },
  { label: "ORG", text: /(пана|панотець|дядько|дядько)\s*\d+(\W+)(у|в|\s)?/gi },
  { label: "LOC", text: /(\w+)\s*(\d+) (у|в|лява/права)/g },
  { label: "PERIOD", text: /(2019|2022)\s*\w*$/gi },
  { label: "QUANT", text: /\d+./g },
  { label: "MISC", text: /(\w+)\s*\w+\s*\w+/gi },
  { label: "ART", text: /(\w+) (.*)\s*\w*$/g },
  { label: "DOC", text: /(документ|закон|угодя|паспорт|документ)/gi },
  { label: "JOB", text: /(професія|посада)/gi },
  { label: "TIME", text: /(\d+:\d+)\s*(по|у)\s*\w*$/g },
];

function extractEntities(text, entities) {
  const result = [];
  for (const entity of entities) {
    const regex = new RegExp(entity.text);
    const matches = text.match(regex);
    if (matches) {
      for (const match of matches) {
        result.push({
          label: entity.label,
          text: match.replace(new RegExp(`\\s+`), " "),
        });
      }
    }
  }
  return result;
}

console.log(JSON.stringify(extractEntities(text, entities)));

