for (let i = 0; i < words.length; i++) {
    const word = words[i];
    const regex = /([A-Z][a-z]+|[a-z]+|[A-Z]{2,})|([0-9]+)/gi;
    let match;
    while ((match = regex.exec(word)) !== null) {
        if (match[1] === match[0]) {
            result.push({
                label: 'PERS',
                text: word
            });
        } else {
            switch(match[0]) {
                case 'DATE':
                    result.push({
                        label: 'DATE',
                        text: word
                    });
                    break;
                case 'DOC':
                    result.push({
                        label: 'DOC',
                        text: word
                    });
                    break;
                case 'JOB':
                    result.push({
                        label: 'JOB',
                        text: word
                    });
                    break;
