                case 'ORG':
                    result.push({
                        label: 'ORG',
                        text: word
                    });
                    break;
                case 'PCT':
                    result.push({
                        label: 'PCT',
                        text: word
                    });
                    break;
                case 'PERIOD':
                    result.push({
                        label: 'PERIOD',
                        text: word
                    });
                    break;
                default:
                    if (match[0] === '') {
                        break;
                    } else {
                        result.push({
                            label: 'MISC',
                            text: word
                        });
                    }
            }
        }
    }
}

