import json

def nlp(text):
    # Класи для розсіню тексту
    classes = {
        'ART': [],
        'DATE': [],
        'DOC': [],
        'JOB': [],
        'LOC': [],
        'MON': [],
        'ORG': [],
        'PCT': [],
        'PERIOD': [],
        'PERS': [],
        'QUANT': [],
        'TIME': [],
        'MISC': []
    }

    # Словники для розпізнавання сутності
    stopwords = {
        'післятися', 'бігти', 'насолодіти', 'смірно', 'ковтав',
        'сіло', 'зупинився', 'війшов', 'пішов', 'переставляє', 'лізав'
    }

    # Підрозди для розпізнавання сутності
    prefixes = {
        'на ', 'при ', 'з '
    }

    words = text.split()
    for word in words:
        if word.lower() in stopwords or word.lower() in prefixes:
            continue

        # Ознаку класу
        label = ''
        if word.endswith('у') or word.endswith('а'):
            label = 'ART'
        elif any(word.startswith(prefix) for prefix in prefixes):
            label = 'DOC'
        elif word.isdigit():
            label = 'MON'
        elif len(word) > 3 and word[-4:] == 'ок' and word[:-4] != 'потому':
            label = 'LOC'
        elif label == '':
            label = 'PERIOD'

        # Текст сутності
        text = ''
        if label == 'ART':
            text = word
        elif label == 'DOC':
            if any(word.startswith(prefix) for prefix in prefixes):
                text = word.split()[0]
            else:
                text = word
        elif label == 'JOB':
            if any(word.endswith('й') for word in words):
                text = ''
            else:
                text = word
        elif label == 'LOC':
            if any(word.endswith('ь') for word in words):
                text = ''
            else:
                text = word
        elif label == 'MON':
            text = word
        elif label == 'PERIOD':
            text = word

        # Dodaj до сутності
        classes[label].append((text, len(text)))

    return json.dumps(classes)

print(nlp(text))

