    "text": /(числові значення з одиницями)/i,
  },
  // TIME
  {
    "label": "TIME",
    "text": /(час|весілля)/i,
  },
  // MISC
  {
    "label": "MISC",
    "text": /(?![A-Z ])(?!\w{2,})\S+/
  }
];

const jsonOutput = [];

for (let i = 0; i < text.length; i++) {
  let match;

  while ((match = entities.find((entity) => text.indexOf(entity.text) > -1)) !== undefined) {
    const startIndex = text.lastIndexOf(match.text);
    const endIndex = startIndex + match.text.length;

    jsonOutput.push({
      label: match.label,
      text: text.substring(startIndex, endIndex),
    });

    text = text.replace(text.substring(startIndex, endIndex), '');
  }
}

module.exports = JSON.parse(JSON.stringify(jsonOutput));

