 const nlp = require('nlp-js');
const tokenizer = new nlp.Tokenizer();
const entityExtractor = new nlp.EntityExtractor({
  filters: [
    { type: 'ART' },
    { type: 'DATE' },
    { type: 'DOC' },
    { type: 'JOB' },
    { type: 'LOC' },
    { type: 'MON' },
    { type: 'ORG' },
    { type: 'PCT' },
    { type: 'PERIOD' },
    { type: 'PERS' },
    { type: 'QUANT' },
    { type: 'TIME' },
    { type: 'MISC' }
  ]
});

const text = "Дим заповнив салон. Славко рвонув ручку і відчинив дверцята кабіни.";
const jsonText = []

try {
  const entities = await entityExtractor.extractEntities(tokenizer.tokenize(text));
  for (let i = 0; i < entities.length; i++) {
    if(entities[i].type == "MISC") continue;

    const { label, text: entityText } = entities[i];

    jsonText.push({
      label: label,
      text: entityText
    });
  }
} catch (e) {
  console.error(e);
}

module.exports = jsonText;

