const entities = [
  { label: "ART", text: /([A-Z][a-z]+|[а-zА-Яа-я])/g },
  { label: "DATE", text: /(\d{1,2}[\s.-]\d{1,2}[\s.-]\d{4})/g },
  { label: "DOC", text: /([ДдкРрвВвеЕеОоАаБбСс]\d{1,2}(?: [\w\s]*\d{1,2})?)/g },
  { label: "JOB", text: /(\w+),(?:\s+[\w\s]+)?/g },
  { label: "LOC", text: /([КкрПпвВвгГгДдЛлжЖж]\d{1,2}[\s.-])/g },
  { label: "MON", text: /(\d+(?:\.\d+)?)(?:[^\w\s])/g },
  { label: "ORG", text: /([БбКкРрВвСс]\w+\b)/g },
  { label: "PCT", text: /(%?\d+)(?:\.\d+)?/g },
  { label: "PERIOD", text: /(\d{1,2}[\s.-]\d{1,2}[\s.-]\d{4})/g },
  { label: "PERS", text: /([АаБбВвГгДдЕеИиОоПпРрСсТтУуФфХхЦцЧчШшЫьъЬьЭэЮюяЯя])/g },
  { label: "QUANT", text: /(\d+(?:\.\d+)?)/g },
  { label: "TIME", text: /([\s.-]\d{1,2}:\d{2}(?:[\s.-]\d{2})?)/g },
  { label: "MISC", text: /(?:[^\w\s])/g }
];

const json = [];

text.match entities.forEach(entity => {
  json.push({
    label: entity.label,
    text: entity.text
  });
});

console.log(json);

