  // MISC
];

const json = entities.map((entity) => {
    return {
      "label": entity.name.toLowerCase().replace(/([а-яА-Я])/g, '-$1'),
      "text": text.match(new RegExp(entity.name, 'g'))?.[0].trim(),
    };
  });

