function getLabel(word) {
    switch (word) {
        case 'коханка':
            return 'PERS';
        case 'місце':
            return 'LOC';
        case 'коханця':
            return 'PERS';
        case 'жіно':
            return 'MISC';
        default:
            return 'MISC';
    }
}

