import json
from nltk import pos_tag, word_tokenize
from nltk.tokenize import word_tokenize
from collections import defaultdict
import re


class NER:
    def __init__(self):
        self.ner_tags = {
            'ART': r'\w+',
            'DATE': r'\d{1,2} \w{3} \d{4}',
            'DOC': r' zakони|угодя|паспорт|документи',
            'JOB': r'[a-z]+ [A-Z]{2}',
            'LOC': r'Ужгород|Львов|Закарпатська область',
            'MON': r'\d{1,3} \w{3} \d{4}',
            'ORG': r'Міністерство економіки|Закарпатський державний університет',
            'PCT': r'%[0-9]{2,4}%',
            'PERIOD': r'[0-9]{1,2} \w{3} \d{4}',
            'PERS': r'\b\w+\s\w+\b',
            'QUANT': r'\d+[ \.,]?\d+',
            'TIME': r'[0-9]{1,2} \w{3} \d{4}',
            'MISC': r'.*\b'
        }

    def process_text(self, text):
        tokens = word_tokenize(text)
        tagged_tokens = pos_tag(tokens)

        # Класифікація та збагачення сутності
        ner_dict = defaultdict(list)
        for word, tag in tagged_tokens:
            found = False
            for key, pattern in self.ner_tags.items():
                if re.search(pattern, word):
                    ner_dict[key].append((word, tag))
                    found = True
            if not found:
                ner_dict['MISC'].append((word, tag))

        # Виведення сутностей у форматі JSON
        json_output = []
        for key, value in ner_dict.items():
            for item in value:
                json_output.append({
                    "label": key,
                    "text": item[0]
                })

        return json.dumps(json_output)


ner_system = NER()
print(ner_system.process_text("Міністерство економіки 22 лютого погодило Закарпатському державному університетові застосування процедури закупівлі «у одного учасника» послуг з оренди кількох об'єктів в Ужгороді для розміщення навчальних аудиторій та інших приміщень університету."))

