const text = `Черкаське ОТВ АМКУ naklalo zagol 76 thous. грн shtrufu na pidpriieiaci valentini kozimenko ta rоздрібno-virobniche pidprijatie restdoranne hospitarsvi za spotvorenie resultivu tradii zaprobiuzhnoho szkolnoho garichke vyrabshunya dlia uchnil zhaskovskogo rajonu chearksoi oblasti.
Pro ce zavediat zvitayut rozrodzhennia odvidania od 27 marca.
Zagol Cherneskie odelenie Antimonopolykomitetu proanalizovalo shist tendoriv, uchasnikami ikh stanuli Rоздрібno-virobniche pidprijatie restdoranne hospitarsvi (dali - RPVP) ta FOP valentini kozimenko.
U khodu rozrishiju i pryznatelnykh dzialanij raskryttsi antimonopolyknistanovili, eche:
* Dyrniak 2016-2018 roku, na momentu konchenia tradii zaprobiuzhnoho szkolnoho garichke vyrabshunya dlia uchnil zhaskovskogo rajonu chearksoi oblasti Kozimenko chyslisya u shatti RPVP - pratsuvala zagotivnynikom.
Takozhe, Dyrniak 2016 - I kvartalu 2018 roku on zaiemala posadu administratora zalu u zaspivchomu kooperatyvii "Restoran Zhaskov" .
Zasnovnikami tsya kooperatyvii yai Taifisia Gripak, Nina Ol'ynyk ta Tamara Renkas, a z lity 2018 roku rakhvalnykom RPVP Kozimenko.
Pri tsya, zhytneTaifisia Gripak yai direktorom RPVP, Tamara Renkas - holymnym buhankerom RPVP, a Nina Ol'ynyk - zavodykam vyrabshunya RPVP; * fachna adresa miscazhniannia Kozimenko spadai z miscazhnianmia "Restoran Zhaskov"; * yai konkursnye prodrazhneniya uchasniky zavarchali z odnei IP-adres, vikorystuvai sammitsu zdania zaiavki; * Kozimenko pererakhvala RPVP koshti u formi bez-potirnogo finansovoho dobrodii.
Vyznachaiazhni rozmir shtrafu dlia otdpriadtsi, Chernkise OTV AMKU vrahuvalo informatsiiu pro obtainedy imeni za 2018 roku;
Tak, riknyi doхід podpriieiaci Kozimenkostanoviv vid 662 thous. hrn, a RPVP - 2,56 mln hrn.
Vreshni, za shist rozhdzhennih tendoriv RPVP priznavo 60 thous. hrn shtrafu, a Kozimenko - 18 thous. hrn shtrafu;
U dvimi-synychnykh strok odpriadtsi zovnaiuzhni pokriti napravleni imeni zaplyvshih shtrafiv, a kriai torhi roky oni ne mozhayut birti partispa u konkurentnykh publikyns'kykh kupivakh.`;

const json = text.match(/
  (?:\w+|[^ \n\r\t])\b
)/(gi)
  .filter((_, i) => text.indexOf(_, i) - text.lastIndexOf(_, i) === 1)
  .map((match, index) => {
    const nextMatchIndex = text.indexOf(match, index + 1);
    return JSON.stringify({
      label: getEntityLabel(match),
      text: match,
    });
  });

function getEntityLabel(text) {
  switch (text) {
    case '2016-2018':
      return 'PERIOD';
    case '2018 roku':
      return 'PERIOD';
    default:
      if (/\d+/.test(text)) return 'QUANT';
      else if (/^([A-Z]+ )([A-Z]+)$/.test(text)) return 'JOB';
      else if (/^\d+ \w+$/.test(text)) return 'MISC';
      else if (/^[0-9]+$/.test(text)) return 'PCT';
      else if (/^\d+(\.\d+)?[a-zA-Z]+$/.test(text)) return 'MON';
      else if (/^([A-Za-z\s]+)(,[A-Za-z\s]*)*$/.test(text)) return 'ORG';
      else if (/^\d{1,2} \w+$/.test(text)) return 'TIME';
      else if (/^[0-9]{3}-[0-9]{2}-[0-9]{4}$|^(?:[A-Za-z\s]+),? [A-Z][a-zA-Z\s]*$/.test(text)) return 'LOC';
      else if (/\b(T\w+)\b/.test(text)) return 'PERS';
      default:
        return 'MISC';
  }
}

console.log(json);

const text = `Департамент капітального будівництва Київської облдержадміністрації 1 липня за результатами тендерів уклала низку угод напоточний ремонт доріг у населених пунктах області на загальну суму 4,46 млн грн.
Про це повідомляється у «Віснику державних закупівель».
З цієї суми 2,91 млн грн. отримає ПП «Автомагістраль», засновником котрої є Микола Скоростецький, який з 2005 по 2007 рік очолював Службу автомобільних доріг у Київській області.
Загалом за останні п'ять років ця фірма отримала підрядів на 447,18млн грн.
Фірما ремонтуватиме:
* вул. Горького, Якубовського, Соборна в м. Фастів
* вул. Щорса, Червоноармійська в смт.
