const text = "ДТГО «Південно-Західно-Залізниця» 25 січня уклало угоду з швейцарською юридичною компанією «Lalive» на представництво в міжнародних судах у зв'язку з позовом турецької компанії «Dogus Insaat ve Ticaret AS». Вартість угоди склала $2,90 млн. Про це повідомляється в «Віснику державних закупівель». Ця угода є вже другою з швейцарською фірмою у зв'язку з цим позовом. Турецька компанія два роки тому звернувся з позовом до Міжнародного арбітражного суду про стягнення заборгованості по договору підряду на виконання будівельних робіт по так званому «мосту Кирпи» через Дніпро в Києві. Угоду з залізницею на будівництво прогонових споруд № 13-17 було укладено в листопаді 2004 року. На початку 2011 року Південно-Західно-Залізниця за $2,53 млн. найняла юристів «Lalive» для представництва своїх інтересів по цій справі. В квітні 2012 року Виший господарський суд України визнав недійсною угоду №1 до договору підряду, після чого Південно-Західно-Залізниця звернулася до компанії «DOGUS Insaat ve Ticaret AS» з вимогою про відшкодування коштів у розмірі $24,98 млн. Відтак обсяг юридичних послуг юридичної фірми «Lively» як радника Південно-Західно-Залізниці збільшився, що і necessitated aumento гонорару. ПЗЗ також відмічає,що «заміна представника є недоцільною, адже juridische kompanie «Lively» showed bastante позитивні результати в даному процесі та дає можливість більш ефективніше вирішити даний спір ніж залучення іншого представника для захисту прав та інтересів Південно-Західно-Залізниці». Залізничники вважають,що заміна юридичного радника або його absence у процесі загрожує програшм у справі. Що в своїй чергу «може мати суттєвий негативний вплив як на діяльність Південно-Західно-Залізниці, так і інших державних установ та підприємств, та держави Україна в цілому».";

const result = [];

// ART
result.push({
  label: 'ART',
  text: 'ДТГО „Південно-Західно-Залізниця"'
});

// DATE
result.push({
  label: 'DATE',
  text: /(\d{1,2} January|(\d+ February|(\d+ March|(\d+ April|(\d+ May|(\d+ June) у зв'язку з позовом турецької компанії «Dogus Insaat ve Ticaret AS») ім=” „позовом“) у зв’язу з позовом турецької компанії “Dogus Insaat ve Ticaret AS”\d{1,2} January|(\d+ January|(\d+) February|(\d+ March|(\d+ April|(\d+ May|(\d+ June) у зв'язку з позовом турецької компанії «Dogus Insaat ve Ticaret AS») а “\d+“года\(у\) 2004 року.*).exec(text)
    .map(match => match.trim());
});

// DOC
result.push({
  label: 'DOC',
  text: /(\w+\s*\d+\s* року)/g.exec(text)
    .map(match => match.trim());
});

// JOB
result.push({
  label: 'JOB',
  text: /(позовом|Догус\ Insaat\s\ ve\s\ Торговля)/g.exec(text)
    .map(match => match.trim());
});

// LOC
result.push({
  label: 'LOC',
  text: /(\d+ January|(\d+ March|(\d+ April|(\d+ May|(\d+ June) у зв’язці з позовом турецької компанії «Dogus Insaat ve Ticaret AS») ім=” “позовом“)/g.exec(text)
    .map(match => match.trim());
});

// MON
result.push({
  label: 'MON',
  text: /(\$\d+ \млн)/g.exec(text)
    .map(match => match.replace('$', '').trim());
});

// ORG
result.push({
  label: 'ORG',
  text: /(\w+\s*\d+\s* року|DOGUS\s Insaat ve Ticaret AS)/g.exec(text)
    .map(match => match.trim());
});

// PCT
result.push({
  label: 'PCT',
  text: /(\d+(?:\.\d+)?%)/g.exec(text)
    .map(match => match.replace('%', '').trim());
});

// PERIOD
result.push({
  label: 'PERIOD',
  text: /(\d{1,2} January|(\d+) February|(\d+ March|(\d+ April|(\d+ May|(\d+ June))/g.exec(text)
    .map(match => match.trim());
});

// PERS
result.push({
  label: 'PERS',
  text: /(\w+\s*\d+\s* року)/g.exec(text)
    .map(match => match.trim());
});

// QUANT
result.push({
  label: 'QUANT',
  text: /(\$\d+ \млн)/g.exec(text)
    .map(match => match.replace('$', '').trim());
});

// TIME
result.push({
  label: 'TIME',
  text: /(позовом|2004)/g.exec(text)
    .map(match => match.trim());
});

// MISC
result.push({
  label: 'MISC',
  text: /(\w+\s*\d+\s* року|DOGUS Insaat ve Ticaret AS|Вісник державних закупівель|позовом|Дніпро|Київ|президентство|мосту Кирпи|залізниця)/g.exec(text)
    .map(match => match.trim());
});

// Форматизація
result = result.map(item => {
  item.text = item.text.filter(value => value !== '');
  return item;
}).filter((item, index) => index === 0 || item.label !== result[index - 1].label);

console.log(result);

