    "label": item.label,
    "text": item.text
  };
}).filter((item, index, arr) => {
  const lastItem = arr[arr.length - 1];
  if (index === 0 || item.label !== lastItem.label) {
    return true;
  }
  if (item.text[0] === "'") {
    return true;
  }
  return false;
});

