const entities = [];

const patterns = [
    /(\w+ с\.)/,
    /(\d{1,3}(,\d{3})*(\.\d{3})?)/,
    /(')(\d{1,2}-\d{2})(\s*(а|а|а|а)?\s*\d{4}(\s* року)?)/,
    /(\w+ ц./),
    /\((\w+), (\w+)\)/,
    /(['"]?)((?:\w\s*)+)(['"]?)/,
];

const regexes = patterns.map(p => new RegExp(`^${p}$`, 'g'));

text.matchAll(regexes).forEach(m => {
    let entity;

    if (m[0].includes('с')) {
        const words = m[0].split(' ').map(w => w.replace(' с', '').trim());
        entity = { label: 'ART', text: words.join(' ') };
    } else if (m[0] === `\d{1,3}(,\d{3})*(\.\d{3})?`) {
        const match = m[0].match(/\d{1,3}(,\d{3})*(\.\d{3})/);
        entity = { label: 'MON', text: match[0] };
    } else if (m[0] === `( \w+), (\w+)`) {
        const words = m[0].split(' ').map(w => w.replace(/[(),]/g, '').trim());
        entity = { label: 'JOB', text: `${words[1]} ${words[0]}` };
    } else if (m[0].includes('(') && m[0].endsWith(')')) {
        const match = m[0].match(/\((\w+)\s*(а|а|а|а)?\s*\d{4}(\s* року)?/);
        entity = { label: 'PERIOD', text: match[1] };
    } else if (m[0].includes('ц')) {
        const words = m[0].split(' ').map(w => w.replace(' ц', '').trim());
        entity = { label: 'DOC', text: words.join(' ') };
    } else if (m[0] === `['"]((?:\w\s*)+)['"]`) {
        entity = { label: 'PERS', text: m[1].slice(0, -1) };
    }

    if (entity) {
        entities.push(entity);
    }
});

const output = JSON.stringify(entities);

console.log(output);

