function extractEntities(text) {
  const entities = [];
  const patterns = [
    { regex: /(?<label>ART|DATE|DOC|JOB|LOC|MON|ORG|PCT|PERIOD|PERS|QUANT|TIME|MISC)\s*(?<text>.+?)/g, 
        label: (match) => match.groups['label'],
        text: (match) => match.groups['text'] },
  ];

  for(let pattern of patterns){
      const regex = new RegExp(pattern.regex);
      let match;
      while ((match = regex.exec(text)) !== null){
          entities.push({ label: pattern.label, text: match[1] });
      }
  }

  return entities;
}

const jsonEntities = extractEntities(text).map(entity => ({ label: entity.label, text: entity.text }));

console.log(jsonEntities);

